import{bV as e,aL as o,u as l,G as i}from"./chunks/framework.BfzMay2U.js";const u=JSON.parse('{"title":"一致性 Hash 算法","description":"","frontmatter":{},"headers":[],"relativePath":"posts/unique-hash-algom.md","filePath":"posts/unique-hash-algom.md"}'),s={name:"posts/unique-hash-algom.md"};function t(h,a,c,d,r,p){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="一致性-hash-算法" tabindex="-1">一致性 Hash 算法 <a class="header-anchor" href="#一致性-hash-算法" aria-label="Permalink to &quot;一致性 Hash 算法&quot;">​</a></h1><ul><li><code>hash</code>值是非负的整数，值的范围构成一个圆环，值为 2^32</li><li>集群节点按照一定规则求<code>hash</code>值，然后放到环中</li><li>对数据<code>key</code>求<code>hash</code>值，然后放到环中，再按照顺时针方向找到最近的节点，保存到上面。</li></ul><p>给定一个圆环，值为<code>2^32</code></p><p>假设现在有 3 个节点：A、B、C</p><p>通过计算求得<code>hash</code>值，放到环中，有几种情况发生：</p><ol><li>三个分别在不同的地方，</li><li>三个可能紧挨着</li><li>或者其中几个紧挨着</li></ol><p>都在不同的地方还好，如果此时有数据需要保存，不同的地方，则能均匀的去存储数据，如果紧挨着，就会有某一个节点不会去存储数据，某一个节点会压力很大。</p><p>一致性<code>Hash</code>算法给出的解决办法就是，它会给你自动创建几个虚拟节点：a、b、c</p><ul><li>虚拟节点 a 对应真实节点 A</li><li>虚拟节点 b 对应真实节点 B</li><li>虚拟节点 c 对应真实节点 C</li></ul><p>再次放入环中，就可以避免某一个节点压力过大的情况。</p><h3 id="新增节点" tabindex="-1">新增节点 <a class="header-anchor" href="#新增节点" aria-label="Permalink to &quot;新增节点&quot;">​</a></h3><p>通过计算<code>hash</code>值放入环中，对于其逆时针方向的数据则会受到影响，顺时针方向的还是会存储到顺时针方向的下一个节点上；逆时针方向上的数据则需要从原来存储的节点上迁移出数据到新的节点上，而不会去影响别的节点或者数据</p><h3 id="删除节点" tabindex="-1">删除节点 <a class="header-anchor" href="#删除节点" aria-label="Permalink to &quot;删除节点&quot;">​</a></h3><p>影响的还是那一个方向上的数据，仅仅需要将移除的节点的上的数据迁移到下一个顺时针方向的节点即可。</p>',14)])])}const _=e(s,[["render",t]]);export{u as __pageData,_ as default};
